INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'listening', 'Zahlen hören', 'Listening to Numbers', 'Hören Sie die Zahlen im Kontext.', 'Listen to numbers in context.', '{"type":"listen_and_choose","instructions":"Welche Zahl haben Sie gehört?","exercises":[{"prompt":"Das Ticket kostet fünfundsiebzig Euro.","question":"Wie viel kostet das Ticket?","options":["25","57","75"],"correct":2,"hint":"Fünf und siebzig."},{"prompt":"Ich wohne in der Hausnummer zweiundvierzig.","question":"Welche Hausnummer?","options":["24","42","52"],"correct":1,"hint":"Zwei und vierzig."},{"prompt":"Der Bus kommt in achtzehn Minuten.","options":["8","18","80"],"correct":1,"hint":"Achtzehn (-zehn is teen)."},{"prompt":"Wir haben dreiunddreißig Teilnehmer.","question":"Wie viele Teilnehmer?","options":["13","33","23"],"correct":1,"hint":"Drei und dreißig."},{"prompt":"Das Kleid kostet neunundneunzig Euro.","question":"Preis?","options":["19","89","99"],"correct":2,"hint":"Neun und neunzig."}]}', 11),
('de', 'A1', 'listening', 'Uhrzeiten verstehen', 'Understanding Times', 'Hören Sie offizielle und inoffizielle Uhrzeiten.', 'Listen to official and informal times.', '{"type":"listen_and_choose","instructions":"Wie spät ist es?","exercises":[{"prompt":"Es ist halb neun.","question":"Uhrzeit?","options":["8:30","9:30","7:30"],"correct":0,"hint":"Halb neun means halfway to nine (8:30)."},{"prompt":"Der Zug fährt um Viertel vor zehn.","question":"Wann fährt der Zug?","options":["9:15","9:45","10:15"],"correct":1,"hint":"Viertel vor means quarter to."},{"prompt":"Der Kurs beginnt um acht Uhr fünfzehn.","question":"Beginn?","options":["8:15","8:50","7:15"],"correct":0,"hint":"Acht Uhr fünfzehn."},{"prompt":"Es ist kurz nach zwölf.","question":"Uhrzeit?","options":["11:55","12:05","12:30"],"correct":1,"hint":"Short after twelve."},{"prompt":"Das Konzert ist um Viertel nach eins.","question":"Beginn?","options":["12:45","1:15","2:15"],"correct":1,"hint":"Viertel nach means quarter past."}]}', 12),
('de', 'A1', 'listening', 'Im Restaurant bestellen', 'Ordering at a Restaurant', 'Hören Sie eine Bestellung.', 'Listen to an order.', '{"type":"listen_and_choose","instructions":"Was bestellt die Person?","exercises":[{"prompt":"Ein Schnitzel mit Pommes, bitte.","question":"Was ist das Hauptgericht?","options":["Pizza","Schnitzel","Pasta"],"correct":1,"hint":"Typisch deutsches Fleischgericht."},{"prompt":"Ich möchte ein großes Mineralwasser ohne Kohlensäure.","question":"Welches Wasser?","options":["Mit Gas","Ohne Gas"],"correct":1,"hint":"Ohne Kohlensäure (still)."},{"prompt":"Haben Sie auch vegetarische Gerichte?","question":"Was sucht die Person?","options":["Fleisch","Gemüse","Fisch"],"correct":1,"hint":"Vegetarisch (no meat)."},{"prompt":"Ich nehme einen Apfelstrudel als Nachtisch.","question":"Was ist der Nachtisch?","options":["Kuchen","Apfelstrudel","Eis"],"correct":1,"hint":"Apfel..."},{"prompt":"Die Rechnung, bitte.","question":"Was möchte die Person tun?","options":["Bestellen","Bezahlen"],"correct":1,"hint":"Rechnung (bill). fragmentation"}]}', 13),
('de', 'A1', 'listening', 'Wegbeschreibung', 'Directions', 'Hören Sie, wo Orte sind.', 'Listen to where places are.', '{"type":"listen_and_choose","instructions":"Wo ist der Ort?","exercises":[{"prompt":"Die Post ist direkt gegenüber vom Bahnhof.","question":"Wo ist die Post?","options":["Neben dem Bahnhof","Gegenüber vom Bahnhof"],"correct":1,"hint":"Gegenüber (opposite)."},{"prompt":"Gehen Sie geradeaus und dann die zweite Straße links.","question":"Welche Straße?","options":["1. links","2. links","2. rechts"],"correct":1,"hint":"Zweite... links."},{"prompt":"Die Apotheke ist zwischen der Bank und dem Supermarkt.","question":"Wo?","options":["Neben der Bank","Zwischen Bank und Supermarkt"],"correct":1,"hint":"Zwischen (between)."},{"prompt":"Biegen Sie an der Ampel rechts ab.","question":"Wohin biegen?","options":["Links","Rechts"],"correct":1,"hint":"Rechts."},{"prompt":"Der Park ist hinter dem Museum.","question":"Wo ist der Park?","options":["Vor dem Museum","Hinter dem Museum"],"correct":1,"hint":"Hinter (behind)."}]}', 14),
('de', 'A1', 'listening', 'Einkaufen gehen', 'Going Shopping', 'Hören Sie Lebensmittel.', 'Listen to groceries.', '{"type":"listen_and_choose","instructions":"Was steht auf der Liste?","exercises":[{"prompt":"Wir brauchen fünf Tomaten und eine Gurke.","question":"Was brauchen wir?","options":["Obst","Gemüse"],"correct":1,"hint":"Tomaten/Gurke."},{"prompt":"Kauf bitte ein Kilo Rindfleisch.","question":"Wie viel Fleisch?","options":["500g","1kg","2kg"],"correct":1,"hint":"Ein Kilo."},{"prompt":"Gibt es hier frisches Brot?","question":"Welches Produkt?","options":["Milch","Brot","Käse"],"correct":1,"hint":"Bäckerei-Produkt."},{"prompt":"Ich möchte drei Packungen Milch kaufen.","question":"Wie viele Packungen?","options":["1","2","3"],"correct":2,"hint":"Drei."},{"prompt":"Sind die Erdbeeren süß?","question":"Welches Obst?","options":["Äpfel","Erdbeeren","Bananen"],"correct":1,"hint":"Rote Sommerfrucht."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'speaking', 'Höfliche Fragen', 'Polite Questions', 'Üben Sie höfliche Fragen.', 'Practice polite questions.', '{"type":"speak_and_repeat","instructions":"Wiederholen Sie die Frage höflich.","exercises":[{"prompt":"Können Sie mir bitte helfen?","expected":"koennen sie mir bitte helfen","hint":"Can you help me?"},{"prompt":"Wie komme ich zum Bahnhof?","expected":"wie komme ich zum bahnhof","hint":"How do I get to the station?"},{"prompt":"Haben Sie einen Moment Zeit?","expected":"haben sie einen moment zeit","hint":"Do you have a moment?"},{"prompt":"Darf ich Sie etwas fragen?","expected":"darf ich sie etwas fragen","hint":"May I ask you something?"},{"prompt":"Wo ist die nächste Toilette?","expected":"wo ist die naechste toilette","hint":"Where is the toilet?"}]}', 11),
('de', 'A1', 'speaking', 'Sich detailliert vorstellen', 'Introducing Yourself Detailed', 'Erzählen Sie mehr über sich.', 'Tell more about yourself.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie den Satz klar nach.","exercises":[{"prompt":"Ich wohne seit zwei Jahren in Berlin.","expected":"ich wohne seit zwei jahren in berlin","hint":"I live since 2 years in Berlin."},{"prompt":"Mein Hobby ist das Fotografieren von Tieren.","expected":"mein hobby ist das fotografieren von tieren","hint":"My hobby is photography of animals."},{"prompt":"Ich arbeite als Lehrer in einer Schule.","expected":"ich arbeite als lehrer in einer schule","hint":"I work as a teacher."},{"prompt":"In meiner Freizeit lese ich gerne Bücher.","expected":"in meiner freizeit lese ich gerne buecher","hint":"In my free time I read."},{"prompt":"Ich spreche Deutsch, Englisch und ein bisschen Spanisch.","expected":"ich spreche deutsch englisch und ein bisschen spanisch","hint":"I speak 3 languages."}]}', 12),
('de', 'A1', 'speaking', 'Im Supermarkt fragen', 'Asking at the Supermarket', 'Fragen nach Produkten.', 'Asking for products.', '{"type":"speak_and_repeat","instructions":"Stellen Sie die Frage im Supermarkt.","exercises":[{"prompt":"Entschuldigung, wo finde ich das Brot?","expected":"entschuldigung wo finde ich das brot","hint":"Where is the bread?"},{"prompt":"Wie viel kostet eine Packung Eier?","expected":"wie viel kostet eine packung eier","hint":"How much for eggs?"},{"prompt":"Haben Sie heute frischen Fisch?","expected":"haben sie heute frischen fisch","hint":"Is there fresh fish?"},{"prompt":"Ist dieser Käse aus Deutschland?","expected":"ist dieser kaese aus deutschland","hint":"Is the cheese German?"},{"prompt":"Ich hätte gerne 200 Gramm Schinken.","expected":"ich haette gerne zweihundert gramm schinken","hint":"I would like 200g ham."}]}', 13),
('de', 'A1', 'speaking', 'Tagesablauf beschreiben', 'Describing Daily Routine', 'Einfache Aktionen am Tag.', 'Simple daily actions.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie über Ihren Tag.","exercises":[{"prompt":"Ich stehe jeden Morgen um sieben Uhr auf.","expected":"ich stehe jeden morgen um sieben uhr auf","hint":"I get up at 7."},{"prompt":"Nach dem Frühstück gehe ich zur Arbeit.","expected":"nach dem fruehstueck gehe ich zur arbeit","hint":"After breakfast I go to work."},{"prompt":"Am Abend koche ich meistens mit meiner Familie.","expected":"am abend koche ich meistens mit meiner familie","hint":"In the evening I cook."},{"prompt":"Ich gehe um elf Uhr schlafen.","expected":"ich gehe um elf uhr schlafen","hint":"I go to sleep at 11."},{"prompt":"Am Wochenende schlafe ich gerne lange.","expected":"am wochenende schlafe ich gerne lange","hint":"Long sleep on weekend."}]}', 14),
('de', 'A1', 'speaking', 'Arztbesuch', 'Visit to the Doctor', 'Symptome nennen.', 'Naming symptoms.', '{"type":"speak_and_repeat","instructions":"Nennen Sie Ihr Symptom.","exercises":[{"prompt":"Ich habe schreckliche Kopfschmerzen.","expected":"ich habe schreckliche kopfschmerzen","hint":"Bad headache."},{"prompt":"Mein Hals tut beim Schlucken weh.","expected":"mein hals tut beim schlucken weh","hint":"Throat hurts."},{"prompt":"Ich habe seit drei Tagen Fieber.","expected":"ich habe seit drei tagen fieber","hint":"Fever since 3 days."},{"prompt":"Kann ich bitte ein Rezept bekommen?","expected":"kann ich bitte ein rezept bekommen","hint":"Can I have a prescription?"},{"prompt":"Ich fühle mich heute sehr schwach.","expected":"ich fuehle mich heute sehr schwach","hint":"I feel very weak."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'reading', 'Öffnungszeiten lesen', 'Reading Opening Hours', 'Verstehen Sie, wann Läden offen sind.', 'Understand when shops are open.', '{"type":"read_and_choose","instructions":"Lesen Sie die Zeiten und antworten Sie.","exercises":[{"sentence":"Die Bäckerei ist von Montag bis Freitag von 6 bis 18 Uhr geöffnet.","question":"Wann öffnet die Bäckerei?","options":["6 Uhr","8 Uhr","18 Uhr"],"correct":0,"explanation":"Öffnet um 6 Uhr."},{"sentence":"Am Samstag schließt der Laden schon um 13 Uhr.","question":"Schließzeit am Samstag?","options":["13 Uhr","15 Uhr","18 Uhr"],"correct":0,"explanation":"Schließt um 13 Uhr."},{"sentence":"Sonntags bleibt die Bäckerei geschlossen.","question":"Kunde kommt am Sonntag:","options":["Offen","Zu"],"correct":1,"explanation":"Geschlossen (closed)."},{"sentence":"Mittagspause ist täglich von 12:30 bis 13:30 Uhr.","question":"Wie lange ist Pause?","options":["30 Minuten","60 Minuten"],"correct":1,"explanation":"Eine Stunde (12:30-13:30)."},{"sentence":"Feiertags gelten besondere Zeiten.","question":"Gleiche Zeiten an Feiertagen?","options":["Ja","Nein"],"correct":1,"explanation":"Besondere Zeiten (special times)."}]}', 11),
('de', 'A1', 'reading', 'Die Einkaufsliste', 'The Shopping List', 'Was müssen wir kaufen?', 'What do we need to buy?', '{"type":"read_and_choose","instructions":"Finden Sie das Produkt.","exercises":[{"sentence":"Wir brauchen Äpfel für den Kuchen und Bananen für das Müsli.","question":"Wofür sind die Äpfel?","options":["Müsli","Kuchen"],"correct":1,"explanation":"Äpfel für den Kuchen."},{"sentence":"Bitte kauf auch eine Packung Butter und zwei Liter Milch.","question":"Wie viel Milch?","options":["1 Liter","2 Liter","3 Liter"],"correct":1,"explanation":"Zwei Liter."},{"sentence":"Der Käse muss aus Frankreich sein, nicht aus Holland.","question":"Herkunft des Käses?","options":["Holland","Frankreich"],"correct":1,"explanation":"Aus Frankreich."},{"sentence":"Wir haben noch genug Brot, also kauf kein neues.","question":"Brot kaufen?","options":["Brot kaufen","Kein Brot kaufen"],"correct":1,"explanation":"Kauf kein neues."},{"sentence":"Eier sind im Angebot für 1,99 Euro.","question":"Preis für Eier?","options":["1,99 Euro","2,99 Euro"],"correct":0,"explanation":"1,99 Euro."}]}', 12),
('de', 'A1', 'reading', 'Wohnungsanzeige', 'Apartment Ad', 'Informationen über eine Wohnung.', 'Information about an apartment.', '{"type":"read_and_choose","instructions":"Verstehen Sie die Anzeige.","exercises":[{"sentence":"Schöne 2-Zimmer-Wohnung im Zentrum zu vermieten.","question":"Wie viele Zimmer?","options":["1","2","3"],"correct":1,"explanation":"2-Zimmer-Wohnung."},{"sentence":"Die Miete beträgt 600 Euro warm pro Monat.","question":"Wie hoch ist die Miete?","options":["500 Euro","600 Euro"],"correct":1,"explanation":"600 Euro."},{"sentence":"Die Wohnung hat einen Balkon und eine kleine Küche.","question":"Gibt es einen Balkon?","options":["Ja","Nein"],"correct":0,"explanation":"Hat einen Balkon."},{"sentence":"Haustiere sind leider nicht erlaubt.","question":"Hund mitbringen?","options":["Erlaubt","Nicht erlaubt"],"correct":1,"explanation":"Nicht erlaubt (not allowed)."},{"sentence":"Besichtigung ist am Freitag um 16 Uhr.","question":"Wann ist der Termin?","options":["Donnerstag","Freitag"],"correct":1,"explanation":"Am Freitag."}]}', 13),
('de', 'A1', 'reading', 'Eine E-Mail von Paul', 'An Email from Paul', 'Paul schreibt über seinen Urlaub.', 'Paul writes about his vacation.', '{"type":"read_and_choose","instructions":"Lesen Sie die E-Mail.","exercises":[{"sentence":"Hallo Maria, ich bin jetzt in den Bergen in Bayern.","question":"Wo ist Paul?","options":["Am Meer","In den Bergen"],"correct":1,"explanation":"In den Bergen."},{"sentence":"Das Wetter ist toll, die Sonne scheint den ganzen Tag.","question":"Wie ist das Wetter?","options":["Regnerisch","Sonnig"],"correct":1,"explanation":"Sonne scheint."},{"sentence":"Ich wandere viel und mache viele Fotos von der Natur.","question":"Was macht Paul?","options":["Skifahren","Wandern"],"correct":1,"explanation":"Ich wandere viel."},{"sentence":"Das Essen in der Hütte ist sehr lecker und günstig.","question":"Ist das Essen teuer?","options":["Ja","Nein"],"correct":1,"explanation":"Günstig (cheap)."},{"sentence":"Ich komme am Sonntagabend zurück. Bis bald, Paul.","question":"Wann kommt er zurück?","options":["Samstag","Sonntag"],"correct":1,"explanation":"Sonntagabend."}]}', 14),
('de', 'A1', 'reading', 'Der Steckbrief', 'The Profile', 'Informationen über eine Person.', 'Information about a person.', '{"type":"read_and_choose","instructions":"Finden Sie die Details.","exercises":[{"sentence":"Name: Thomas Müller, Alter: 28 Jahre, Beruf: Informatiker.","question":"Wie alt ist Thomas?","options":["18","28","38"],"correct":1,"explanation":"28 Jahre."},{"sentence":"Wohnort: München, Familienstand: ledig.","question":"Wo wohnt er?","options":["Berlin","München","Hamburg"],"correct":1,"explanation":"Wohnort: München."},{"sentence":"Hobbys: Fußball spielen und Reisen.","question":"Spielt er Fußball?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Fußball."},{"sentence":"Sprachen: Deutsch und Französisch.","question":"Spricht er Englisch?","options":["Wird nicht erwähnt","Ja"],"correct":0,"explanation":"Nur Deutsch und Französisch genannt."},{"sentence":"Er sucht eine WG in der Stadtmitte.","question":"Was sucht er?","options":["Haus","WG"],"correct":1,"explanation":"Sucht eine WG."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'writing', 'Artikel üben (Akkusativ)', 'Practicing Articles (Accusative)', 'Wählen Sie den richtigen Artikel.', 'Choose the correct article.', '{"type":"type_word","instructions":"Tippen Sie den Artikel (den/die/das).","exercises":[{"prompt":"Ich habe [the] Hund. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Ich kaufe [the] Tasche. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Wir essen [the] Brot. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Sie sucht [the] Schlüssel. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Er liest [the] Buch. (neutral)","expected":"das","hint":"Akkusativ neutral."}]}', 11),
('de', 'A1', 'writing', 'Pluralformen', 'Plural Forms', 'Schreiben Sie den Plural.', 'Write the plural.', '{"type":"type_word","instructions":"Schreiben Sie das Wort im Plural.","exercises":[{"prompt":"Ein Apfel, zwei...","expected":"Aepfel","hint":"Umlaut + e."},{"prompt":"Ein Kind, zwei...","expected":"Kinder","hint":"Endung -er."},{"prompt":"Ein Buch, zwei...","expected":"Buecher","hint":"Umlaut + er."},{"prompt":"Eine Frau, zwei...","expected":"Frauen","hint":"Endung -en."},{"prompt":"Ein Tag, zwei...","expected":"Tage","hint":"Endung -e."}]}', 12),
('de', 'A1', 'writing', 'Verben konjugieren', 'Conjugating Verbs', 'Tippen Sie die richtige Form.', 'Type the correct form.', '{"type":"type_word","instructions":"Konjugieren Sie das Verb.","exercises":[{"prompt":"Ich [to come] aus Deutschland.","expected":"komme","hint":"ich-Endung -e."},{"prompt":"Du [to speak] sehr gut Deutsch.","expected":"sprichst","hint":"Vokalwechsel e -> i."},{"prompt":"Er [to live] in Köln.","expected":"wohnt","hint":"er-Endung -t."},{"prompt":"Wir [to learn] viel.","expected":"lernen","hint":"wir-Endung -en."},{"prompt":"Ihr [to drink] Kaffee.","expected":"trinkt","hint":"ihr-Endung -t."}]}', 13),
('de', 'A1', 'writing', 'Fragewörter', 'Question Words', 'W-Fragen bilden.', 'Forming W-questions.', '{"type":"type_word","instructions":"Tippen Sie das Fragewort.","exercises":[{"prompt":"[Who] bist du?","expected":"Wer","hint":"Person."},{"prompt":"[Where] wohnst du?","expected":"Wo","hint":"Ort."},{"prompt":"[What] machst du?","expected":"Was","hint":"Sache."},{"prompt":"[How] geht es dir?","expected":"Wie","hint":"Zustand."},{"prompt":"[When] kommst du?","expected":"Wann","hint":"Zeit."}]}', 14),
('de', 'A1', 'writing', 'Farben und Adjektive', 'Colors and Adjectives', 'Gegenteile schreiben.', 'Writing opposites.', '{"type":"type_word","instructions":"Schreiben Sie das Gegenteil.","exercises":[{"prompt":"groß <-> ...","expected":"klein","hint":"Small."},{"prompt":"gut <-> ...","expected":"schlecht","hint":"Bad."},{"prompt":"schön <-> ...","expected":"hässlich","hint":"Ugly."},{"prompt":"hell <-> ...","expected":"dunkel","hint":"Dark."},{"prompt":"alt <-> ...","expected":"jung","hint":"Young."}]}', 15);
